import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const baseUrl = process.env.APP_BASE_URL;
  const apiKey = process.env.PLATFORM_API_KEY;
  const selfRunId = input.runId || input.instanceId || input._runId;
  if (!baseUrl || !apiKey) { console.error('APP_BASE_URL or PLATFORM_API_KEY missing'); process.exit(1); }
  const url = `${baseUrl}/api/runs?workflow=mediforce-ai-developer&status=running&limit=100`;
  const res = await fetch(url, { headers: { 'X-Api-Key': apiKey, Accept: 'application/json' } });
  if (!res.ok) { const body = await res.text(); console.error(`runs API ${res.status}: ${body.slice(0,300)}`); process.exit(1); }
  const data = await res.json();
  const others = (data.runs || []).filter((r) => r.runId !== selfRunId);
  const skip = others.length > 0;
  console.log(`Singleton check: ${others.length} other running run(s) — ${skip ? 'SKIP' : 'PROCEED'}`);
  writeFileSync('/output/result.json', JSON.stringify({ skip, otherRunIds: others.map((r) => r.runId), summary: skip ? `Another run is active (${others[0].runId}) — skipping.` : 'No other run active — proceeding.' }));
} catch (err) {
  console.error('check-singleton crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const REPO = 'Appsilon/mediforce';
  const READY_LABEL = 'mediforce-ai-developer';
  const LOCK_LABEL = 'mediforce-ai-in-progress';
  const token = process.env.GITHUB_TOKEN;
  if (!token) { console.error('GITHUB_TOKEN missing'); process.exit(1); }
  const ghHeaders = { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' };
  const url = new URL(`https://api.github.com/repos/${REPO}/issues`);
  url.searchParams.set('state', 'open');
  url.searchParams.set('labels', READY_LABEL);
  url.searchParams.set('sort', 'created');
  url.searchParams.set('direction', 'asc');
  url.searchParams.set('per_page', '50');
  const res = await fetch(url, { headers: ghHeaders });
  if (!res.ok) { const body = await res.text(); console.error(`GitHub list issues ${res.status}: ${body.slice(0,300)}`); process.exit(1); }
  const all = await res.json();
  const candidates = all.filter((i) => !i.pull_request).filter((i) => !(i.labels || []).some((l) => (typeof l === 'string' ? l : l.name) === LOCK_LABEL));
  if (candidates.length === 0) {
    console.log(`No eligible issue (checked ${all.length} with label=${READY_LABEL})`);
    writeFileSync('/output/result.json', JSON.stringify({ noIssue: true, summary: `No issue ready (label=${READY_LABEL}, not ${LOCK_LABEL}).` }));
    process.exit(0);
  }
  const issue = candidates[0];
  console.log(`Picked #${issue.number}: ${issue.title}`);
  const lockRes = await fetch(`https://api.github.com/repos/${REPO}/issues/${issue.number}/labels`, {
    method: 'POST',
    headers: { ...ghHeaders, 'Content-Type': 'application/json' },
    body: JSON.stringify({ labels: [LOCK_LABEL] }),
  });
  if (!lockRes.ok) { const body = await lockRes.text(); console.error(`GitHub add lock label ${lockRes.status}: ${body.slice(0,300)}`); process.exit(1); }
  const slug = (issue.title || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 40) || 'task';
  const branch = `mediforce-ai/issue-${issue.number}-${slug}`;
  writeFileSync('/output/result.json', JSON.stringify({
    noIssue: false,
    repo: REPO,
    issueNumber: issue.number,
    issueTitle: issue.title,
    issueBody: issue.body || '',
    issueUrl: issue.html_url,
    issueLabels: (issue.labels || []).map((l) => (typeof l === 'string' ? l : l.name)),
    branch,
    lockLabel: LOCK_LABEL,
    summary: `Picked issue #${issue.number} — ${issue.title}. Locked with '${LOCK_LABEL}'.`,
  }));
} catch (err) {
  console.error('pick-issue crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const REPO = 'Appsilon/mediforce';
  const LOCK_LABEL = 'mediforce-ai-in-progress';
  const issueNumber = input.steps?.['pick-issue']?.issueNumber ?? input.issueNumber;
  const token = process.env.GITHUB_TOKEN;
  if (!issueNumber) { console.log('cleanup: no issueNumber in upstream — nothing to do'); writeFileSync('/output/result.json', JSON.stringify({ cleaned: false, reason: 'no issueNumber' })); process.exit(0); }
  if (!token) { console.error('GITHUB_TOKEN missing'); process.exit(1); }
  const url = `https://api.github.com/repos/${REPO}/issues/${issueNumber}/labels/${encodeURIComponent(LOCK_LABEL)}`;
  const res = await fetch(url, { method: 'DELETE', headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' } });
  if (res.status === 404) { console.log(`cleanup: label '${LOCK_LABEL}' not present on #${issueNumber} — ok`); }
  else if (!res.ok) { const body = await res.text(); console.error(`GitHub DELETE label ${res.status}: ${body.slice(0,300)}`); process.exit(1); }
  else { console.log(`cleanup: removed '${LOCK_LABEL}' from #${issueNumber}`); }
  writeFileSync('/output/result.json', JSON.stringify({ cleaned: true, issueNumber, labelRemoved: LOCK_LABEL }));
} catch (err) {
  console.error('cleanup crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}
